const _body = $json.body || $json; if (_body._smoke_test) return [{ json: { ok: true, smoke_test: true } }];
// ---- Pillar 3: Threat Assessor — keyword overlap + Groq → threat_score ----
// Input: { url, domain, title, content_preview }
//   OR:  { batch: true }  — process all unscored articles from Supabase
// Groq 8b classifies HIGH/MEDIUM/LOW based on Markexis keyword cluster overlap
// Updates competitor_articles.threat_score + keyword_overlap[]
const ENV = (typeof $env !== 'undefined' && $env) ? $env : process.env;
const b = $json.body || $json;

// Markexis keyword clusters to check against (from CLAUDE.md)
const MARKEXIS_KEYWORDS = [
  // Cluster 1 - LatAm
  'latam market entry', 'latin america', 'mexico market', 'brazil market',
  'colombia', 'latam gtm', 'latin america business', 'latam expansion',
  // Cluster 2 - AI Marketing
  'ai implementation marketing', 'ai marketing strategy', 'ai sales marketing',
  'marketing automation', 'artificial intelligence marketing', 'ai go-to-market',
  // Cluster 3 - Revenue Growth / GTM
  'b2b gtm strategy', 'go-to-market consulting', 'revenue growth strategy',
  'b2b pipeline', 'saas gtm', 'marketing sales alignment', 'cac reduction',
  'b2b lead generation', 'gtm strategy', 'go-to-market',
  // Cluster 4 - Competitor overlap
  'latam expansion consulting', 'gtm consulting', 'b2b growth consulting',
  'revenue growth consultant'
];

const SYSTEM_PROMPT = `You are a competitive intelligence analyst for Markexis — a B2B consulting firm specializing in:
1. LatAm Market Entry (Mexico, Brazil, Colombia, Argentina, Chile)
2. AI Implementation in Marketing & Sales
3. Revenue Growth & GTM Strategy

Analyze the competitor article and assess its threat level to Markexis.

HIGH: Directly competes with Markexis's core services. Targets same ICP (B2B SaaS, Fintech, 20-500 employees). Covers LatAm market entry, AI marketing implementation, or GTM strategy in depth. Could rank for Markexis's primary keywords.

MEDIUM: Covers adjacent topics. May steal some traffic but doesn't directly compete. Mentions B2B marketing, growth, or LatAm tangentially.

LOW: General marketing content, B2C focused, or completely off-topic.

Return JSON only: { "threat_score": "HIGH"|"MEDIUM"|"LOW", "keyword_overlap": ["kw1","kw2",...], "reasoning": "one sentence" }`;

async function assessArticle(url, domain, title, preview) {
  const USER = `Competitor: ${domain}\nArticle: "${title}"\nContent preview: ${(preview || '').slice(0, 1500)}\n\nMarkexis keywords to check overlap with:\n${MARKEXIS_KEYWORDS.join(', ')}\n\nAssess threat level:`;

  const providers = [
    { url: 'https://api.groq.com/openai/v1/chat/completions', key: ENV.GROQ_API_KEY, model: 'llama-3.1-8b-instant' },
    { url: 'https://api.cerebras.ai/v1/chat/completions', key: ENV.CEREBRAS_API_KEY, model: 'llama3.1-70b' }
  ];

  for (const p of providers) {
    if (!p.key) continue;
    try {
      const res = await this.helpers.httpRequest({
        method: 'POST', url: p.url,
        headers: { Authorization: `Bearer ${p.key}`, 'Content-Type': 'application/json' },
        body: JSON.stringify({
          model: p.model,
          messages: [{ role: 'system', content: SYSTEM_PROMPT }, { role: 'user', content: USER }],
          temperature: 0.2, max_tokens: 256, response_format: { type: 'json_object' }
        }),
        json: true, timeout: 20000
      });
      return JSON.parse(res.choices[0].message.content);
    } catch { continue; }
  }
  return null;
}

// Single article mode (called from content-extractor)
if (b.url && !b.batch) {
  const result = await assessArticle.call(this, b.url, b.domain, b.title, b.content_preview);
  if (!result) return [{ json: { ok: false, error: 'LLM unavailable', url: b.url } }];

  if (ENV.SUPABASE_URL) {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: `${ENV.SUPABASE_URL}/rest/v1/competitor_articles?url=eq.${encodeURIComponent(b.url)}`,
      headers: {
        apikey: ENV.SUPABASE_ANON_KEY, Authorization: `Bearer ${ENV.SUPABASE_ANON_KEY}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        threat_score: result.threat_score,
        keyword_overlap: result.keyword_overlap || []
      }),
      json: false, timeout: 10000
    }).catch(() => null);
  }

  return [{ json: { ok: true, url: b.url, ...result } }];
}

// Batch mode: pull unscored articles from Supabase and assess all
const unscored = ENV.SUPABASE_URL ? await this.helpers.httpRequest({
  method: 'GET',
  url: `${ENV.SUPABASE_URL}/rest/v1/competitor_articles?threat_score=is.null&select=url,competitor_domain,title,meta_description&limit=20`,
  headers: { apikey: ENV.SUPABASE_ANON_KEY, Authorization: `Bearer ${ENV.SUPABASE_ANON_KEY}` },
  json: true, timeout: 10000
}).catch(() => []) : [];

if (!unscored.length) return [{ json: { ok: true, message: 'No unscored articles found', assessed: 0 } }];

const batchResults = await Promise.allSettled(
  unscored.map(async (article) => {
    const result = await assessArticle.call(this, article.url, article.competitor_domain, article.title, article.meta_description);
    if (!result || !ENV.SUPABASE_URL) return { ...article, skipped: true };
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: `${ENV.SUPABASE_URL}/rest/v1/competitor_articles?url=eq.${encodeURIComponent(article.url)}`,
      headers: {
        apikey: ENV.SUPABASE_ANON_KEY, Authorization: `Bearer ${ENV.SUPABASE_ANON_KEY}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({ threat_score: result.threat_score, keyword_overlap: result.keyword_overlap || [] }),
      json: false, timeout: 10000
    }).catch(() => null);
    return { url: article.url, domain: article.competitor_domain, ...result };
  })
);

const assessed = batchResults.filter(r => r.status === 'fulfilled').map(r => r.value);
const high = assessed.filter(a => a.threat_score === 'HIGH').length;

return [{ json: { ok: true, assessed: assessed.length, high_threats: high, results: assessed } }];
